630	\subsection{Mathlib gap and design}
631	
632	There is no $\AffineCoverMVSquare$ analog in Mathlib; the abstract $\MayerVietorisSquare$ exists for any preordered category with a Grothendieck topology, but the affineness conditions (which are scheme-specific) are not in scope at that level. The iter-028 scaffold introduces the bundled scheme-flavored structure, with the four corner accessors definitionally equal to $U_1 \sqcap U_2$, $U_1$, $U_2$, $U_1 \sqcup U_2$ via the Mathlib $\Opens.\mayerVietorisSquare$ constructor (probe-confirmed $\rfl$, see Lemma~\ref{lem:Scheme_AffineCoverMVSquare_corners}). The cover hypothesis $\cover \,\colon\, U_1 \sqcup U_2 = \top$ is recorded but not consumed by $\toMayerVietorisSquare$; iter-029+ Serre-finiteness lemmas will use it to identify $X_4$ with $\top$ and hence read off cohomology of the whole scheme $X$.
633	
634	\begin{definition}[2-affine MV square on a scheme, iter-028]
635	  \label{def:Scheme_AffineCoverMVSquare}
636	  \lean{AlgebraicGeometry.Scheme.AffineCoverMVSquare}
637	  \uses{def:Scheme_HModule_prime}
638	  Let $X : \Scheme.\{u\}$. The structure $X.\AffineCoverMVSquare$ has fields
639	  \begin{itemize}
640	    \item $U_1, U_2 : X.\Opens$ (two open subschemes of $X$);
641	    \item $\mathtt{isAffineOpen\_U_1} \,\colon\, \IsAffineOpen\,U_1$;
642	    \item $\mathtt{isAffineOpen\_U_2} \,\colon\, \IsAffineOpen\,U_2$;
643	    \item $\mathtt{isAffineOpen\_inf} \,\colon\, \IsAffineOpen\,(U_1 \sqcap U_2)$;
644	    \item $\cover \,\colon\, U_1 \sqcup U_2 = \top$.
645	  \end{itemize}
646	  Equivalently: a $2$-affine open cover of $X$ together with the hypothesis that the pairwise intersection is affine.
647	\end{definition}
648	
649	\begin{definition}[Underlying Mayer-Vietoris square accessor, iter-028]
650	  \label{def:Scheme_AffineCoverMVSquare_toMayerVietorisSquare}
651	  \lean{AlgebraicGeometry.Scheme.AffineCoverMVSquare.toMayerVietorisSquare}
652	  \uses{def:Scheme_AffineCoverMVSquare}
653	  Let $X : \Scheme.\{u\}$ and $S : X.\AffineCoverMVSquare$. The underlying abstract MV square is
654	  \[
655	    S.\toMayerVietorisSquare \;:=\; \Opens.\mayerVietorisSquare\,S.U_1\,S.U_2 \;\colon\; (\Opens.\grothendieckTopology\,X.\toTopCat).\MayerVietorisSquare.
656	  \]
657	  This is the bridge from the geometric input (the bundled affine cover $S$) to the categorical input (a $\MayerVietorisSquare$) the abstract MV-LES theorem $\HModulePrime\_\mathtt{sequence\_exact}$ consumes.
658	\end{definition}
659	
660	\begin{lemma}[Corner identifications, iter-028]
661	  \label{lem:Scheme_AffineCoverMVSquare_corners}
662	  \uses{def:Scheme_AffineCoverMVSquare_toMayerVietorisSquare}
663	  In the setting of Definition~\ref{def:Scheme_AffineCoverMVSquare_toMayerVietorisSquare} the four corners of $S.\toMayerVietorisSquare$ collapse to
664	  \[
665	    X_1 = U_1 \sqcap U_2, \quad X_2 = U_1, \quad X_3 = U_2, \quad X_4 = U_1 \sqcup U_2,
666	  \]
667	  where each equality holds by $\rfl$. (The plan-agent probe in iter-028 confirms the four \lstinline{rfl}-equalities; they are not formalised as named lemmas but are recorded here for downstream consumers' definitional unfolding.)
668	\end{lemma}
669	
670	\subsection{Use in Serre finiteness}
671	
672	For a proper geometrically integral $k$-curve $C$ a $2$-affine cover with affine intersection always exists (e.g.\ remove a closed point to get one affine, remove another to get the second; their intersection is the curve minus two points, again affine on a $k$-curve). The bundle $C.\AffineCoverMVSquare$ then feeds the iter-029+ Serre-finiteness chain:
673	\begin{enumerate}
674	  \item The MV-LES applied to $S.\toMayerVietorisSquare$ and $\toModuleKSheaf\,C$ gives a $5$-term sequence relating $H^0$ and $H^1$ of $X = \top$, $U_1$, $U_2$, $U_1 \cap U_2$.
675	  \item The cover hypothesis $S.\cover \,\colon\, U_1 \sqcup U_2 = \top$ identifies the $X_4$ piece with $\top$ (i.e.\ all of $C$).
676	  \item The affineness of $U_1$, $U_2$, $U_1 \cap U_2$ collapses $H^{>0}$ on those pieces (Serre vanishing on affines), reducing the LES to a $3$-term sequence relating $H^0(C, \mathcal O_C)$, $H^0(U_j, \mathcal O)$ and $H^1(C, \mathcal O_C)$.
677	  \item Each $H^0$ piece is a $k$-module given by a finite ring computation, hence finite-dimensional, hence so is $H^1$.
678	\end{enumerate}
679	Step 4 is the actual Serre finiteness; iter-028 lands only the bundle structure $\AffineCoverMVSquare$ and the abstract-MV-square accessor $\toMayerVietorisSquare$. The remaining steps are iter-029+ work.
